{
  "formal_minutes": {
    "회의명": "UI Theme Package Release Readiness",
    "프로젝트코드": "PUBLIC_MEETING_SMOKE",
    "참석자": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "주제": "공개 릴리스 목표 시점",
        "결정": "스모크 테스트가 통과하는 경우 금요일 15:00 KST를 공개 릴리스 목표로 한다."
      },
      {
        "주제": "packageName mismatch 대응",
        "결정": "packageName mismatch가 발생하면 먼저 package config를 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다."
      }
    ],
    "rejected_proposals": [
      {
        "주제": "smoke-theme-pack.mjs 처리 방식",
        "제안": "packageName mismatch를 무시하도록 변경하자",
        "결론": "거부됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "주제": "수요일 릴리스 제안",
        "내용": "수요일 릴리스 제안은 내부 스트레치 목표일 뿐, 최종 공개 릴리스 결정은 아니다."
      }
    ],
    "non_decisions": [
      {
        "주제": "README 설치 단계 검토",
        "내용": "목요일까지 가능하면 검토하자는 언급은 있었으나 담당자 지정은 없었다."
      }
    ],
    "risks": [
      {
        "위험": "잘못된 tarball 경로",
        "영향": "릴리스 지연 가능"
      },
      {
        "위험": "README 설치 단계가 오래되었을 가능성",
        "영향": "릴리스 노트가 사용자에게 오해를 줄 수 있음"
      }
    ],
    "open_questions": [
      {
        "질문": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "질문": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "미완료",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 failure triage note를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "미완료",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "대기",
      "source_certainty": "confirmed"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 목요일까지 가능하면 검토한다.",
      "due": "목요일 가능 시",
      "status": "담당자 미지정",
      "source_certainty": "mentioned_not_assigned"
    }
  ],
  "followup_note": {
    "next_checks": [
      "Minjun의 스모크 테스트 결과 통과 여부를 확인한다.",
      "Doyun의 triage note 작성 완료 여부를 확인한다.",
      "스모크 결과 공유 후 Hara의 tarball 경로 점검 결과를 확인한다.",
      "README 설치 단계 검토 담당자를 지정할지 확인한다.",
      "최종 릴리스 승인 권한자를 명확히 한다.",
      "릴리스 노트에 수요일 내부 스트레치 목표를 언급할지 결정한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 관련 사실",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "명시되지 않은 담당자",
      "명시되지 않은 마감기한"
    ]
  },
  "non_invention_rules": [
    "인라인 공개용 synthetic fixture에 있는 사실만 사용한다.",
    "확정 결정과 거부된 제안, 내부 스트레치 목표, 리스크, 미해결 질문을 분리한다.",
    "고객, 예산, 보안, 장애, 법무, 담당자, 마감에 관한 미기재 사실은 추가하지 않는다.",
    "답이 없는 항목은 추정하지 말고 미정 또는 미확정으로 유지한다."
  ]
}
